// app/api/og/route.tsx
// Dynamic Open Graph image generator
// Renders a branded 1200×630 image for social sharing
// Supports both generic and event-specific OG images via query params
//
// Usage:
//   /api/og                               → default brand image
//   /api/og?event=NBA+Finals&city=Boston  → event-specific image

import { ImageResponse } from 'next/og'
import { NextRequest } from 'next/server'

export const runtime = 'edge'

export async function GET(req: NextRequest) {
  const { searchParams } = req.nextUrl

  const eventName = searchParams.get('event') ?? ''
  const city      = searchParams.get('city')  ?? ''
  const eventType = searchParams.get('type')  ?? 'sports' // sports | music | festival

  const isEventSpecific = Boolean(eventName)

  // Accent colour per event type
  const accent =
    eventType === 'music'    ? '#8B5CF6' :
    eventType === 'festival' ? '#F97316' :
    '#0EA5E9' // sky blue default

  const bgGradient =
    eventType === 'music'    ? 'linear-gradient(135deg, #1E0B4B 0%, #4C1D95 50%, #7C3AED 100%)' :
    eventType === 'festival' ? 'linear-gradient(135deg, #431407 0%, #C2410C 50%, #F97316 100%)' :
    'linear-gradient(135deg, #0C4A6E 0%, #0369A1 50%, #0EA5E9 100%)'

  const logoSrc = 'data:image/png;base64,'

  return new ImageResponse(
    (
      <div
        style={{
          width:          '1200px',
          height:         '630px',
          display:        'flex',
          flexDirection:  'column',
          background:     bgGradient,
          position:       'relative',
          overflow:       'hidden',
          fontFamily:     'system-ui, -apple-system, sans-serif',
        }}
      >
        {/* Background pattern */}
        <div style={{
          position:   'absolute', inset: 0,
          backgroundImage: 'radial-gradient(circle at 1px 1px, rgba(255,255,255,0.08) 1px, transparent 0)',
          backgroundSize: '40px 40px',
        }} />

        {/* Glow orb */}
        <div style={{
          position:     'absolute',
          right:        '-100px',
          top:          '-100px',
          width:        '600px',
          height:       '600px',
          borderRadius: '50%',
          background:   'rgba(255,255,255,0.06)',
        }} />

        {/* Content */}
        <div style={{
          display:        'flex',
          flexDirection:  'column',
          justifyContent: 'space-between',
          height:         '100%',
          padding:        '60px 72px',
          position:       'relative',
          zIndex:         1,
        }}>

          {/* Top row — logo + badge */}
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            {/* GT Logo */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
              <img
                src={logoSrc}
                width={64}
                height={64}
                style={{ borderRadius: '16px', boxShadow: '0 4px 20px rgba(0,0,0,0.3)' }}
              />
              <span style={{ fontSize: '26px', fontWeight: '800', color: 'white', letterSpacing: '-0.5px' }}>
                Gladys Travel
              </span>
            </div>

            {/* AI badge */}
            <div style={{
              background:   'rgba(255,255,255,0.15)',
              border:       '1.5px solid rgba(255,255,255,0.3)',
              borderRadius: '100px',
              padding:      '8px 20px',
              fontSize:     '15px',
              fontWeight:   '700',
              color:        'white',
            }}>
              ✦ AI Travel Companion
            </div>
          </div>

          {/* Main content */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            {isEventSpecific ? (
              <>
                {/* Event label */}
                <div style={{
                  background:   'rgba(255,255,255,0.15)',
                  border:       '1.5px solid rgba(255,255,255,0.25)',
                  borderRadius: '100px',
                  padding:      '6px 18px',
                  fontSize:     '15px',
                  fontWeight:   '700',
                  color:        'rgba(255,255,255,0.85)',
                  display:      'inline-flex',
                  width:        'fit-content',
                }}>
                  {eventType === 'music' ? '🎵' : eventType === 'festival' ? '🎪' : '⚽'} {city ? `${city} ·` : ''} Complete Trip Plan
                </div>

                {/* Event name */}
                <div style={{
                  fontSize:   eventName.length > 40 ? '52px' : '64px',
                  fontWeight: '900',
                  color:      'white',
                  lineHeight: '1.1',
                  letterSpacing: '-2px',
                  maxWidth:   '900px',
                }}>
                  {eventName}
                </div>

                {/* Subline */}
                <div style={{
                  fontSize:   '24px',
                  fontWeight: '500',
                  color:      'rgba(255,255,255,0.7)',
                  letterSpacing: '-0.3px',
                }}>
                  Flights · Hotels · Tickets · Local tips — all in one plan
                </div>
              </>
            ) : (
              <>
                {/* Generic headline */}
                <div style={{
                  fontSize:   '72px',
                  fontWeight: '900',
                  color:      'white',
                  lineHeight: '1.05',
                  letterSpacing: '-2.5px',
                  maxWidth:   '900px',
                }}>
                  Plan trips around events you love.
                </div>

                <div style={{
                  fontSize:   '26px',
                  fontWeight: '500',
                  color:      'rgba(255,255,255,0.75)',
                  letterSpacing: '-0.3px',
                }}>
                  Search any concert, match or festival — get a complete trip in seconds.
                </div>
              </>
            )}
          </div>

          {/* Bottom row — stats */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '48px' }}>
            {[
              { label: 'Sports · Music · Festivals', icon: '🎟' },
              { label: 'Live scores & setlists', icon: '🔴' },
              { label: 'gladystravel.com', icon: '✦' },
            ].map((item, i) => (
              <div key={i} style={{
                display:    'flex',
                alignItems: 'center',
                gap:        '10px',
                color:      'rgba(255,255,255,0.7)',
                fontSize:   '17px',
                fontWeight: '600',
              }}>
                <span style={{ fontSize: '20px' }}>{item.icon}</span>
                {item.label}
              </div>
            ))}
          </div>
        </div>
      </div>
    ),
    {
      width:  1200,
      height: 630,
    }
  )
}